const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split(/\s+/).map(Number);
let idx=0;
const T=input[idx++];
let out=[];
for(let t=0;t<T;t++){
  const N=input[idx++];
  const a=input.slice(idx, idx+N);
  idx+=N;
  let pos=-1;
  for(let i=0;i<N-1;i++) if(a[i]>a[i+1]){pos=i;break;}
  if(pos===-1){out.push('YES'); continue;}
  [a[pos],a[pos+1]]=[a[pos+1],a[pos]];
  let ok=true;
  for(let i=0;i<N-1;i++) if(a[i]>a[i+1]){ok=false;break;}
  out.push(ok?'YES':'NO');
}
console.log(out.join('\n'));
